import React, { useState } from "react";

const LoginPage = () => {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [step, setStep] = useState(1); // Step 1: Login, Step 2: 2-Step Verification, Step 3: Multi-Step Verification
  const [otp, setOtp] = useState(""); // OTP entered by the user
  const [generatedOtp, setGeneratedOtp] = useState(""); // OTP sent to the user
  const [isTwoStepEnabled, setIsTwoStepEnabled] = useState(true); // Simulating stored user setting
  const [isMultiStepEnabled, setIsMultiStepEnabled] = useState(true); // Simulating stored user setting

  // Function to generate a random 6-digit OTP
  const generateOtp = () => Math.floor(100000 + Math.random() * 900000).toString();

  // Handle initial login
  const handleLogin = (e) => {
    e.preventDefault();

    // Simulate authentication success
    console.log("Login successful, checking verification settings...");

    if (isTwoStepEnabled) {
      const newOtp = generateOtp();
      setGeneratedOtp(newOtp);
      alert(`Two-Step OTP: ${newOtp}`); // Simulate sending OTP
      setStep(2); // Move to Two-Step Verification
    } else if (isMultiStepEnabled) {
      const newOtp = generateOtp();
      setGeneratedOtp(newOtp);
      alert(`Multi-Step OTP: ${newOtp}`); // Simulate sending OTP
      setStep(3); // Move to Multi-Step Verification
    } else {
      alert("Login Successful! 🎉");
    }
  };

  // Handle Two-Step Verification
  const handleTwoStepVerification = (e) => {
    e.preventDefault();
    if (otp === generatedOtp) {
      if (isMultiStepEnabled) {
        const newOtp = generateOtp();
        setGeneratedOtp(newOtp);
        setOtp(""); // Clear previous OTP input
        alert(`Multi-Step OTP: ${newOtp}`); // Simulate sending new OTP
        setStep(3); // Move to Multi-Step Verification
      } else {
        alert("Login Successful! 🎉");
      }
    } else {
      alert("Invalid OTP. Please try again.");
    }
  };

  // Handle Multi-Step Verification
  const handleMultiStepVerification = (e) => {
    e.preventDefault();
    if (otp === generatedOtp) {
      alert("Login Successful! 🎉");
    } else {
      alert("Invalid OTP. Please try again.");
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-gray-100">
      <div className="bg-white p-6 rounded-lg shadow-lg w-96">
        <h2 className="text-2xl font-bold text-center mb-4">Login</h2>

        {/* Step 1: Email & Password Login */}
        {step === 1 && (
          <form onSubmit={handleLogin}>
            <div className="mb-4">
              <label className="block text-gray-700 font-semibold">Email</label>
              <input
                type="email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                required
                className="w-full p-2 border rounded-lg focus:border-blue-500"
                placeholder="Enter your email"
              />
            </div>

            <div className="mb-4">
              <label className="block text-gray-700 font-semibold">Password</label>
              <input
                type="password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                required
                className="w-full p-2 border rounded-lg focus:border-blue-500"
                placeholder="Enter your password"
              />
            </div>

            <button
              type="submit"
              className="bg-blue-600 text-white w-full py-2 rounded-lg hover:bg-blue-700"
            >
              Login
            </button>
          </form>
        )}

        {/* Step 2: Two-Step Verification */}
        {step === 2 && (
          <form onSubmit={handleTwoStepVerification}>
            <div className="mb-4">
              <label className="block text-gray-700 font-semibold">Enter Two-Step OTP</label>
              <input
                type="text"
                value={otp}
                onChange={(e) => setOtp(e.target.value)}
                required
                className="w-full p-2 border rounded-lg focus:border-blue-500"
                placeholder="Enter OTP"
              />
            </div>

            <button
              type="submit"
              className="bg-blue-600 text-white w-full py-2 rounded-lg hover:bg-blue-700"
            >
              Verify OTP
            </button>
          </form>
        )}

        {/* Step 3: Multi-Step Verification */}
        {step === 3 && (
          <form onSubmit={handleMultiStepVerification}>
            <div className="mb-4">
              <label className="block text-gray-700 font-semibold">Enter Multi-Step OTP</label>
              <input
                type="text"
                value={otp}
                onChange={(e) => setOtp(e.target.value)}
                required
                className="w-full p-2 border rounded-lg focus:border-blue-500"
                placeholder="Enter OTP"
              />
            </div>

            <button
              type="submit"
              className="bg-blue-600 text-white w-full py-2 rounded-lg hover:bg-blue-700"
            >
              Verify OTP
            </button>
          </form>
        )}
      </div>
    </div>
  );
};

export default LoginPage;
